describe("Temporal.PlainTime",()=>{describe("creation and parsing",()=>{it("can be created from an RFC 9557 string",()=>{let e=Temporal.PlainTime.from("17:01:00");expect(e.toString()).toContain("17:01:00")}),it("can be created from an own object",()=>{let e=Temporal.PlainTime.from("17:01:00"),o=Temporal.PlainTime.from(e);expect(e).toEqual(o)}),it("can be created from an object containing properties",()=>{let e=Temporal.PlainTime.from({hour:19,minute:39,second:9,millisecond:68,microsecond:346,nanosecond:205});expect(e.toString()).toEqual("19:39:09.068346205")})}),describe("arithmetic methods",()=>{let e=Temporal.PlainTime.from("12:00:00"),o=Temporal.PlainTime.from("12:00:01");it("add() advances the time",()=>{let t=e.add({hours:1});expect(t.hour).toBe(13)}),it("compare() method works for two PlainTime objects",()=>{expect(Temporal.PlainTime.compare(e,o)).toBe(-1),expect(Temporal.PlainTime.compare(o,e)).toBe(1),expect(Temporal.PlainTime.compare(e,e)).toBe(0)}),it("equals() verifies if two PlainTime are equal",()=>{let t=Temporal.PlainTime.from("12:00:00");expect(e.equals(t)).toBe(!0)}),it("round() supports various forms, roundingMode, and roundingIncrement",()=>{let t=e.add({milliseconds:500}),r=t.round({smallestUnit:"second"});expect(r.second).toBe(1);let i=t.round({smallestUnit:"second",roundingMode:"trunc"});expect(i.second).toBe(0);let n=e.add({minutes:7,seconds:15}),c=n.round("minute");expect(c.minute).toBe(7),expect(c.second).toBe(0);let s=n.round({smallestUnit:"minute",roundingIncrement:15});expect(s.minute).toBe(0);let a=n.round({smallestUnit:"hour",roundingIncrement:2});expect(a.hour).toBe(12)}),it("since() returns correct duration",()=>{let t=o.since(e);expect(t.sign).toBe(1),expect(t.hours).toBe(0),expect(t.minutes).toBe(0),expect(t.seconds).toBe(1),expect(t.milliseconds).toBe(0),expect(t.microseconds).toBe(0),expect(t.nanoseconds).toBe(0)}),it("subtract() decrements by a duration",()=>{let t=e.subtract({hours:1});expect(t.hour).toBeLessThan(e.hour)}),it("toString() returns an ISO string representation",()=>{let t=e.toString();expect(typeof t).toBe("string"),expect(t).toBe("12:00:00")}),it("until() returns correct duration",()=>{let t=e.until(o);expect(t.sign).toBe(1),expect(t.hours).toBe(0),expect(t.minutes).toBe(0),expect(t.seconds).toBe(1),expect(t.milliseconds).toBe(0),expect(t.microseconds).toBe(0),expect(t.nanoseconds).toBe(0)}),it("valueOf() throws a TypeError",()=>{expect(()=>{+e}).toThrow()}),it("with() method returns a new PlainTime with updated fields",()=>{let t=e.with({hour:15});expect(t.hour).toBe(15)})}),describe("properties",()=>{let e=Temporal.PlainTime.from("12:00:00");it("should have correct date and time properties",()=>{expect(e.hour).toBe(12),expect(e.minute).toBe(0),expect(e.second).toBe(0),expect(e.millisecond).toBe(0),expect(e.microsecond).toBe(0),expect(e.nanosecond).toBe(0)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(e)).toBe("[object Temporal.PlainTime]")})})});
